form:Form.form:Scripts:
	function VALIDAR(myThis)
{						
			if (g_CTRLs['f_ini_t'].GetXValue() > g_CTRLs['f_fin_t'].GetXValue())
				{
					myThis.SetError('El rango de fechas especificado no es correcto');
					return false;						
				}					


			if (g_CTRLs['f_ini_t'].GetXValue() == "" && g_CTRLs['f_fin_t'].GetXValue() != "")
				{
					myThis.SetError('El rango de fechas especificado no es correcto');
					return false;						
				}

			if (g_CTRLs['f_ini_t'].GetXValue() != "" && g_CTRLs['f_fin_t'].GetXValue() == "")
				{
					myThis.SetError('El rango de fechas especificado no es correcto');
					return false;						
				}				

		return true;
	}
